-- ============================================================
-- Greenhouse Board Tokens
-- Generated from greenhouse_valid_tokens.csv
-- Total records: 664
-- ============================================================

CREATE TABLE IF NOT EXISTS api.greenhouse_board_tokens (
    id                  SERIAL          PRIMARY KEY,
    company_name        VARCHAR(255)    NOT NULL,
    board_token         VARCHAR(255)    NOT NULL UNIQUE,
    industry            VARCHAR(255)    NULL,
    status              VARCHAR(50)     NOT NULL DEFAULT 'VALID',
    http_code           SMALLINT        NULL,
    job_count           INT             NULL,
    api_url             VARCHAR(500)    NOT NULL,
    board_url           VARCHAR(500)    NOT NULL,
    created_at          TIMESTAMP       NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at          TIMESTAMP       NOT NULL DEFAULT CURRENT_TIMESTAMP
);
 
CREATE INDEX IF NOT EXISTS idx_gbt_board_token ON greenhouse_board_tokens (board_token);
CREATE INDEX IF NOT EXISTS idx_gbt_industry    ON greenhouse_board_tokens (industry);
CREATE INDEX IF NOT EXISTS idx_gbt_status      ON greenhouse_board_tokens (status);
 
-- Auto-update updated_at on row change
CREATE OR REPLACE FUNCTION fn_set_updated_at()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = CURRENT_TIMESTAMP;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;
 
DROP TRIGGER IF EXISTS trg_gbt_updated_at ON greenhouse_board_tokens;
CREATE TRIGGER trg_gbt_updated_at
    BEFORE UPDATE ON greenhouse_board_tokens
    FOR EACH ROW EXECUTE FUNCTION fn_set_updated_at();


